<?php
if ( ! defined( 'ABSPATH' ) ) { exit; } class TCT_Hex_Grid { const IMAGE_SIZE = 1024; const HEX_RADIUS = 84; const BORDER_WIDTH = 3; const TILE_COUNT = 40; const ROW_PATTERN = array( 7, 6, 7, 6, 7, 7 ); public static function get_reveal_order() { return array( 16, 0, 39, 6, 33, 22, 3, 36, 29, 10, 17, 15, 1, 38, 7, 23, 30, 34, 5, 27, 9, 21, 32, 37, 14, 2, 35, 24, 11, 28, 8, 19, 25, 31, 4, 12, 18, 20, 26, 13, ); } public static function get_revealed_tiles( $progress_pct ) { $progress_pct = (float) $progress_pct; if ( $progress_pct <= 0 ) { return array(); } if ( $progress_pct >= 100 ) { return range( 0, self::TILE_COUNT - 1 ); } $tiles_to_reveal = (int) floor( $progress_pct / 2.5 ); $tiles_to_reveal = max( 0, min( self::TILE_COUNT, $tiles_to_reveal ) ); if ( $tiles_to_reveal <= 0 ) { return array(); } $reveal_order = self::get_reveal_order(); return array_slice( $reveal_order, 0, $tiles_to_reveal ); } public static function get_tile_centers() { $centers = array(); $r = self::HEX_RADIUS; $size = self::IMAGE_SIZE; $hex_width = sqrt( 3 ) * $r; $hex_height = 2 * $r; $horiz_spacing = $hex_width; $vert_spacing = 1.5 * $r; $grid_width = 6 * $horiz_spacing + $hex_width; $grid_height = 5 * $vert_spacing + $hex_height; $grid_start_x = ( $size - $grid_width ) / 2.0; $grid_start_y = ( $size - $grid_height ) / 2.0; $base_x = $grid_start_x + $hex_width / 2.0; $base_y = $grid_start_y + $hex_height / 2.0; $tile_index = 0; foreach ( self::ROW_PATTERN as $row_num => $tiles_in_row ) { $y = $base_y + $row_num * $vert_spacing; $row_offset = ( 6 === $tiles_in_row ) ? $horiz_spacing / 2.0 : 0; $start_x = $base_x + $row_offset; for ( $col = 0; $col < $tiles_in_row; $col++ ) { $x = $start_x + $col * $horiz_spacing; $centers[ $tile_index ] = array( 'x' => $x, 'y' => $y, ); $tile_index++; } } return $centers; } public static function get_hexagon_vertices( $cx, $cy, $r ) { $vertices = array(); for ( $i = 0; $i < 6; $i++ ) { $angle = deg2rad( 60 * $i - 90 ); $vertices[] = array( 'x' => $cx + $r * cos( $angle ), 'y' => $cy + $r * sin( $angle ), ); } return $vertices; } public static function generate_progress_image( $source_path, $progress_pct, &$error = '' ) { $error = ''; if ( ! extension_loaded( 'gd' ) ) { $error = 'GD extension is not loaded.'; return null; } if ( ! file_exists( $source_path ) ) { $error = 'Source image not found: ' . $source_path; return null; } $source_info = @getimagesize( $source_path ); if ( ! $source_info ) { $error = 'Could not read source image dimensions.'; return null; } $mime = isset( $source_info['mime'] ) ? $source_info['mime'] : ''; $source_img = null; switch ( $mime ) { case 'image/jpeg': $source_img = @imagecreatefromjpeg( $source_path ); break; case 'image/png': $source_img = @imagecreatefrompng( $source_path ); break; case 'image/gif': $source_img = @imagecreatefromgif( $source_path ); break; case 'image/webp': if ( function_exists( 'imagecreatefromwebp' ) ) { $source_img = @imagecreatefromwebp( $source_path ); } break; } if ( ! $source_img ) { $error = 'Failed to load source image (unsupported format or corrupt file).'; return null; } $source_width = imagesx( $source_img ); $source_height = imagesy( $source_img ); $resized_source = imagecreatetruecolor( self::IMAGE_SIZE, self::IMAGE_SIZE ); if ( ! $resized_source ) { imagedestroy( $source_img ); $error = 'Failed to create resized source image.'; return null; } imagealphablending( $resized_source, true ); imagesavealpha( $resized_source, true ); $resized = imagecopyresampled( $resized_source, $source_img, 0, 0, 0, 0, self::IMAGE_SIZE, self::IMAGE_SIZE, $source_width, $source_height ); imagedestroy( $source_img ); if ( ! $resized ) { imagedestroy( $resized_source ); $error = 'Failed to resize source image.'; return null; } $canvas = imagecreatetruecolor( self::IMAGE_SIZE, self::IMAGE_SIZE ); if ( ! $canvas ) { imagedestroy( $resized_source ); $error = 'Failed to create output canvas.'; return null; } imagealphablending( $canvas, true ); imagesavealpha( $canvas, true ); $white = imagecolorallocate( $canvas, 255, 255, 255 ); $black = imagecolorallocate( $canvas, 0, 0, 0 ); imagefill( $canvas, 0, 0, $white ); $revealed_tiles = self::get_revealed_tiles( $progress_pct ); $tile_centers = self::get_tile_centers(); $r = self::HEX_RADIUS; foreach ( $revealed_tiles as $tile_index ) { if ( ! isset( $tile_centers[ $tile_index ] ) ) { continue; } $center = $tile_centers[ $tile_index ]; $cx = $center['x']; $cy = $center['y']; $vertices = self::get_hexagon_vertices( $cx, $cy, $r ); self::draw_hexagonal_region( $canvas, $resized_source, $vertices ); } $border_width = self::BORDER_WIDTH; for ( $i = 0; $i < $border_width; $i++ ) { imagerectangle( $canvas, $i, $i, self::IMAGE_SIZE - 1 - $i, self::IMAGE_SIZE - 1 - $i, $black ); } imagedestroy( $resized_source ); ob_start(); $success = imagepng( $canvas, null, 6 ); $bytes = ob_get_clean(); imagedestroy( $canvas ); if ( ! $success || empty( $bytes ) ) { $error = 'Failed to encode image as PNG.'; return null; } return $bytes; } private static function draw_hexagonal_region( $canvas, $source, $vertices ) { if ( empty( $vertices ) || count( $vertices ) < 6 ) { return; } $min_x = PHP_INT_MAX; $max_x = PHP_INT_MIN; $min_y = PHP_INT_MAX; $max_y = PHP_INT_MIN; foreach ( $vertices as $v ) { $min_x = min( $min_x, $v['x'] ); $max_x = max( $max_x, $v['x'] ); $min_y = min( $min_y, $v['y'] ); $max_y = max( $max_y, $v['y'] ); } $min_x = max( 0, (int) floor( $min_x ) ); $max_x = min( self::IMAGE_SIZE - 1, (int) ceil( $max_x ) ); $min_y = max( 0, (int) floor( $min_y ) ); $max_y = min( self::IMAGE_SIZE - 1, (int) ceil( $max_y ) ); if ( $max_x <= $min_x || $max_y <= $min_y ) { return; } for ( $y = $min_y; $y <= $max_y; $y++ ) { for ( $x = $min_x; $x <= $max_x; $x++ ) { if ( self::point_in_polygon( $x + 0.5, $y + 0.5, $vertices ) ) { $color = imagecolorat( $source, $x, $y ); imagesetpixel( $canvas, $x, $y, $color ); } } } } private static function point_in_polygon( $px, $py, $vertices ) { $n = count( $vertices ); if ( $n < 3 ) { return false; } $inside = false; for ( $i = 0, $j = $n - 1; $i < $n; $j = $i++ ) { $xi = $vertices[ $i ]['x']; $yi = $vertices[ $i ]['y']; $xj = $vertices[ $j ]['x']; $yj = $vertices[ $j ]['y']; if ( ( ( $yi > $py ) !== ( $yj > $py ) ) && ( $px < ( $xj - $xi ) * ( $py - $yi ) / ( $yj - $yi ) + $xi ) ) { $inside = ! $inside; } } return $inside; } public static function debug_grid_layout() { $r = self::HEX_RADIUS; $hex_width = sqrt( 3 ) * $r; $hex_height = 2 * $r; $output = "Hexagonal Grid Layout (40 tiles, 7-6-7-6-7-7 pattern)\n"; $output .= "Pointy-topped hexagons\n\n"; $output .= "Geometry:\n"; $output .= sprintf( "  HEX_RADIUS: %d px\n", $r ); $output .= sprintf( "  Hex width: %.1f px\n", $hex_width ); $output .= sprintf( "  Hex height: %.1f px\n", $hex_height ); $output .= sprintf( "  Image size: %d px\n", self::IMAGE_SIZE ); $output .= sprintf( "  Grid width: %.1f px (fits: %s)\n", 6 * $hex_width + $hex_width, ( 7 * $hex_width <= self::IMAGE_SIZE ) ? 'YES' : 'NO' ); $output .= "\n"; $output .= "Grid layout (tile indices):\n"; $tile_index = 0; foreach ( self::ROW_PATTERN as $row_num => $tiles_in_row ) { if ( 6 === $tiles_in_row ) { $output .= '  '; } for ( $col = 0; $col < $tiles_in_row; $col++ ) { $output .= sprintf( '[%02d] ', $tile_index ); $tile_index++; } $output .= "\n"; } $output .= "\nTile centers (corners + center):\n"; $centers = self::get_tile_centers(); $key_tiles = array( 0 => 'top-left', 6 => 'top-right', 16 => 'center', 33 => 'bottom-left', 39 => 'bottom-right', ); foreach ( $key_tiles as $idx => $label ) { if ( isset( $centers[ $idx ] ) ) { $c = $centers[ $idx ]; $output .= sprintf( "  Tile %d (%s): (%.1f, %.1f)\n", $idx, $label, $c['x'], $c['y'] ); } } $output .= "\nReveal order (first 10): "; $reveal_order = self::get_reveal_order(); $output .= implode( ', ', array_slice( $reveal_order, 0, 10 ) ); $output .= "\n"; return $output; } } 
